// Ensemble v1's raw_bull_score / raw_bear_score / final_score drift is EXPECTED — those scores depend on user-configured TradingView inputs (i_execution, i_signal, etc.) that aren't portable to the Python compute(). Filter them out so the Slack channel only surfaces actionable drift.
const module = items[0].json.module;
const suppressed_fields = (module === 'ensemble_engine_v1')
  ? new Set(['raw_bull_score','raw_bear_score','final_score'])
  : new Set();
const real_drift = items[0].json.fields.filter(f =>
  f.verdict === 'DRIFT' && !suppressed_fields.has(f.field));
if (real_drift.length === 0) return [];  // nothing actionable
return [{ json: { ...items[0].json, real_drift } }];
